@* Rendered as interactive island in the static layout *@
@rendermode InteractiveServer
@inject ThemeService ThemeService
@implements IDisposable

<span class="theme-indicator badge" style="background-color: @ThemeService.AccentColor;">
    @ThemeService.Theme
</span>

@code {
    private Action? _handler;

    protected override void OnInitialized()
    {
        _handler = () => InvokeAsync(StateHasChanged);
        ThemeService.OnChange += _handler;
    }

    public void Dispose() => ThemeService.OnChange -= _handler;
}

@inject ThemeService ThemeService
@implements IDisposable

<button class="btn btn-sm btn-outline-secondary" @onclick="Toggle">
    @(ThemeService.Theme switch
    {
        Theme.Light => "☀️ Light",
        Theme.Dark => "🌙 Dark",
        _ => "💻 System"
    })
</button>

@code {
    private Action? _handler;

    protected override void OnInitialized()
    {
        _handler = () => InvokeAsync(StateHasChanged);
        ThemeService.OnChange += _handler;
    }

    private void Toggle()
    {
        var next = ThemeService.Theme switch
        {
            Theme.Light => Theme.Dark,
            Theme.Dark => Theme.System,
            _ => Theme.Light
        };
        ThemeService.SetTheme(next);
    }

    public void Dispose() => ThemeService.OnChange -= _handler;
}

@page "/settings"
@rendermode InteractiveServer
@inject ThemeService ThemeService
@implements IDisposable

<PageTitle>Settings</PageTitle>

<h1>User Preferences</h1>

<div class="mb-3">
    <label class="form-label">Theme</label>
    <select class="form-select w-auto" value="@ThemeService.Theme" @onchange="OnThemeChanged">
        @foreach (var t in Enum.GetValues<Theme>())
        {
            <option value="@t">@t</option>
        }
    </select>
</div>

<div class="mb-3">
    <label class="form-label">Accent Color</label>
    <input type="color" class="form-control form-control-color"
           value="@ThemeService.AccentColor" @onchange="OnAccentChanged" />
</div>

<p>
    Current: <strong>@ThemeService.Theme</strong> /
    <span style="color: @ThemeService.AccentColor;">@ThemeService.AccentColor</span>
</p>

@code {
    private Action? _handler;

    protected override void OnInitialized()
    {
        _handler = () => InvokeAsync(StateHasChanged);
        ThemeService.OnChange += _handler;
    }

    private void OnThemeChanged(ChangeEventArgs e)
    {
        if (Enum.TryParse<Theme>(e.Value?.ToString(), out var theme))
            ThemeService.SetTheme(theme);
    }

    private void OnAccentChanged(ChangeEventArgs e)
    {
        ThemeService.SetAccentColor(e.Value?.ToString() ?? "#0d6efd");
    }

    public void Dispose() => ThemeService.OnChange -= _handler;
}

